// Armazena as imagens em variáveis para o index puxar
const imagensProjetos = {
    projeto1_img1: "data:image/png;base64,",
    projeto2_img1: "data:image/png;base64,COLE_O_CODIGO_BASE64_AQUI",
    projeto2_img2: "data:image/png;base64,COLE_O_CODIGO_BASE64_AQUI"
};

// Função que injeta as imagens no HTML ao carregar a página
window.onload = function() {
    document.getElementById('img-portal-1').src = imagensProjetos.projeto1_img1;
    document.getElementById('img-portal-2').src = imagensProjetos.projeto1_img2;
    document.getElementById('img-painel-1').src = imagensProjetos.projeto2_img1;
    document.getElementById('img-painel-2').src = imagensProjetos.projeto2_img2;
};
